class Solution:
    def reinitializePermutation(self, n):
        pos = 1
        ops = 0
        while True:
            if pos % 2 == 0:
                pos = pos // 2
            else:
                pos = n // 2 + (pos - 1) // 2
            ops += 1
            if pos == 1:
                return ops

