var reinitializePermutation = function(n) {
    let pos = 1;
    let ops = 0;
    while (true) {
        if (pos % 2 === 0) {
            pos = pos / 2;
        } else {
            pos = n / 2 + (pos - 1) / 2;
        }
        ops++;
        if (pos === 1) return ops;
    }
};
